211â†’async function runSingleUpload(
212â†’	flags: UploadFlags,
213â†’	session: string,
214â†’): Promise<void> {
215â†’	const write = (msg: string) => {
216â†’		process.stdout.write(`${msg}\n`);
217â†’	};
218â†’	const writeError = (msg: string) => {
219â†’		process.stderr.write(`${msg}\n`);
220â†’	};
221â†’
222â†’	const credentials = loadCredentials();
223â†’	if (!credentials && !flags.dryRun) {
224â†’		writeError("Error: Not authenticated. Run `rudel login` first.");
225â†’		process.exitCode = 1;
226â†’		return;
227â†’	}
228â†’
229â†’	write(`Resolving session: ${session}`);
230â†’	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
231â†’	try {
232â†’		sessionInfo = await resolveSession(session);
233â†’	} catch (error) {
234â†’		writeError(
235â†’			`Error: ${error instanceof Error ? error.message : String(error)}`,
236â†’		);
237â†’		process.exitCode = 1;
238â†’		return;
239â†’	}
240â†’	write(`Found session at: ${sessionInfo.transcriptPath}`);
241â†’
242â†’	const gitInfo = await getGitInfo(sessionInfo.projectPath);
243â†’	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
244â†’	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
245â†’
246â†’	const organizationId =
247â†’		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
248â†’	if (organizationId) write(`Organization: ${organizationId}`);
249â†’
250â†’	write("Building upload request...");
251â†’	const sessionFile: SessionFile = {
252â†’		sessionId: sessionInfo.sessionId,
253â†’		transcriptPath: sessionInfo.transcriptPath,
254â†’		projectPath: sessionInfo.projectPath,
255â†’	};
256â†’
257â†’	const request = await claudeCodeAdapter.buildUploadRequest(sessionFile, {
258â†’		tag: flags.tag,
259â†’		gitInfo,
260â†’		organizationId,
261â†’	});
262â†’
263â†’	write(`Transcript: ${request.content.length} bytes`);
264â†’	if (request.subagents && request.subagents.length > 0) {
265â†’		write(`Subagents: ${request.subagents.length} file(s)`);
266â†’	}
267â†’
268â†’	if (!flags.tag && flags.classify) {
269â†’		write("Classifying session...");
270â†’		const classified = await classifySession(request.content);
271â†’		if (classified) {
272â†’			(request as { tag?: string }).tag = classified;
273â†’			write(`Classified as: ${classified}`);
274â†’		}
275â†’	}
276â†’
277â†’	if (flags.dryRun) {
278â†’		const preview = {
279â†’			...request,
280â†’			content: `[${request.content.length} bytes]`,
281â†’			subagents: request.subagents?.map((s) => ({
282â†’				...s,
283â†’				content: `[${s.content.length} bytes]`,
284â†’			})),
285â†’		};
286â†’		write("Dry run - would upload:");
287â†’		write(JSON.stringify(preview, null, 2));
288â†’		return;
289â†’	}
290â†’
291â†’	write("Uploading...");
292â†’	const result = await uploadSession(request, {
293â†’		endpoint: flags.endpoint,
294â†’		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
295â†’		token: credentials!.token,
296â†’	});
297â†’
298â†’	if (result.success) {
299â†’		write("Upload successful!");
300â†’	} else {
