306â†’async function runRetryUpload(flags: UploadFlags): Promise<void> {
307â†’	const credentials = loadCredentials();
308â†’	if (!credentials) {
309â†’		p.log.error("Not authenticated. Run `rudel login` first.");
310â†’		process.exitCode = 1;
311â†’		return;
312â†’	}
313â†’
314â†’	p.intro("rudel upload --retry");
315â†’
316â†’	const failures = await loadFailedUploads();
317â†’	if (failures.length === 0) {
318â†’		p.outro("No failed uploads to retry.");
319â†’		return;
320â†’	}
321â†’
322â†’	p.log.info(`Found ${failures.length} failed upload(s):`);
323â†’	for (const f of failures.slice(0, 10)) {
324â†’		p.log.warn(`  ${f.sessionId}: ${f.error} (${f.failedAt})`);
325â†’	}
326â†’	if (failures.length > 10) {
327â†’		p.log.warn(`  ...and ${failures.length - 10} more`);
328â†’	}
329â†’
330â†’	const shouldRetry = await p.confirm({
331â†’		message: `Retry all ${failures.length} failed upload(s)?`,
332â†’		initialValue: true,
333â†’	});
334â†’
335â†’	if (p.isCancel(shouldRetry) || !shouldRetry) {
336â†’		p.cancel("Retry cancelled.");
337â†’		return;
338â†’	}
339â†’
340â†’	const endpoint = flags.endpoint;
341â†’
342â†’	type RetryItem = BatchUploadItem & {
343â†’		failure: (typeof failures)[number];
344â†’	};
345â†’
346â†’	const items: RetryItem[] = failures.map((f) => ({
347â†’		sessionId: f.sessionId,
348â†’		label: f.sessionId,
349â†’		transcriptPath: f.transcriptPath,
350â†’		projectPath: f.projectPath,
351â†’		source: f.source,
352â†’		organizationId: f.organizationId,
353â†’		failure: f,
354â†’	}));
355â†’
356â†’	const summary = await runBatchUpload({
357â†’		items,
358â†’		label: "Retrying uploads...",
359â†’		concurrency: flags.concurrency,
360â†’		upload: async (item, onRetry) => {
361â†’			const adapter = item.failure.source
362â†’				? getAdapter(item.failure.source)
363â†’				: claudeCodeAdapter;
364â†’			const sessionFile: SessionFile = {
365â†’				sessionId: item.failure.sessionId,
366â†’				transcriptPath: item.failure.transcriptPath,
367â†’				projectPath: item.failure.projectPath,
368â†’			};
369â†’			const gitInfo = await getGitInfo(item.failure.projectPath);
370â†’			const organizationId =
371â†’				flags.org ??
372â†’				item.failure.organizationId ??
373â†’				(await getProjectOrgId(item.failure.projectPath));
374â†’
375â†’			const request = await adapter.buildUploadRequest(sessionFile, {
376â†’				tag: flags.tag,
377â†’				gitInfo,
378â†’				organizationId,
379â†’			});
380â†’
381â†’			return uploadSession(request, {
382â†’				endpoint,
383â†’				token: credentials.token,
384â†’				onRetry,
385â†’			});
386â†’		},
387â†’	});
388â†’
389â†’	renderBatchSummary(summary);
390â†’
391â†’	p.outro("Done!");
392â†’
393â†’	if (summary.failed > 0) {
394â†’		process.exitCode = 1;
395â†’	}
396â†’}
