398â†’async function runUpload(
399â†’	flags: UploadFlags,
400â†’	...sessions: string[]
401â†’): Promise<void> {
402â†’	if (flags.retry) {
403â†’		return runRetryUpload(flags);
404â†’	}
405â†’	if (sessions.length === 0) {
406â†’		return runInteractiveUpload(flags);
407â†’	}
408â†’	return runSingleUpload(flags, sessions[0] as string);
409â†’}
