 33â†’export function encodeProjectPath(projectPath: string): string {
 34â†’	return projectPath.replace(/\//g, "-");
 35â†’}
 36â†’
 37â†’export async function decodeProjectPath(encodedDir: string): Promise<string> {
 38â†’	const parts = encodedDir.replace(/^-/, "").split("-");
 39â†’
 40â†’	async function findPath(
 41â†’		partIndex: number,
 42â†’		currentPath: string,
 43â†’	): Promise<string | null> {
 44â†’		if (partIndex >= parts.length) {
 45â†’			try {
 46â†’				await stat(currentPath);
 47â†’				return currentPath;
 48â†’			} catch {
 49â†’				return null;
 50â†’			}
 51â†’		}
 52â†’
 53â†’		for (let endIndex = parts.length; endIndex > partIndex; endIndex--) {
 54â†’			const segment = parts.slice(partIndex, endIndex).join("-");
 55â†’			const testPath = currentPath
 56â†’				? `${currentPath}/${segment}`
 57â†’				: `/${segment}`;
 58â†’
 59â†’			try {
 60â†’				await stat(testPath);
 61â†’				if (endIndex === parts.length) {
 62â†’					return testPath;
 63â†’				}
 64â†’				const result = await findPath(endIndex, testPath);
 65â†’				if (result) {
 66â†’					return result;
 67â†’				}
 68â†’			} catch {
 69â†’				// Path doesn't exist, try shorter segment
 70â†’			}
 71â†’		}
 72â†’
 73â†’		return null;
 74â†’	}
 75â†’
 76â†’	const result = await findPath(0, "");
 77â†’	if (result) {
 78â†’		return result;
 79â†’	}
 80â†’
 81â†’	return `/${parts.join("/")}`;
 82â†’}
