 84â†’export function extractAgentIds(sessionContent: string): string[] {
 85â†’	const agentIds = new Set<string>();
 86â†’
 87â†’	for (const line of sessionContent.split("\n")) {
 88â†’		if (!line.trim()) continue;
 89â†’
 90â†’		try {
 91â†’			const entry = JSON.parse(line);
 92â†’			if (entry.toolUseResult?.agentId) {
 93â†’				agentIds.add(entry.toolUseResult.agentId);
 94â†’			}
 95â†’		} catch {
 96â†’			// Skip malformed lines
 97â†’		}
 98â†’	}
 99â†’
100â†’	return Array.from(agentIds);
101â†’}
