103â†’interface SubagentFile {
104â†’	agentId: string;
105â†’	content: string;
106â†’}
107â†’
108â†’export async function readSubagentFiles(
109â†’	sessionDir: string,
110â†’	agentIds: string[],
111â†’	sessionId?: string,
112â†’): Promise<SubagentFile[]> {
113â†’	const subagents: SubagentFile[] = [];
114â†’
115â†’	for (const agentId of agentIds) {
116â†’		const possiblePaths = [
117â†’			join(sessionDir, `agent-${agentId}.jsonl`),
118â†’			...(sessionId
119â†’				? [join(sessionDir, sessionId, "subagents", `agent-${agentId}.jsonl`)]
120â†’				: []),
121â†’		];
122â†’
123â†’		for (const agentPath of possiblePaths) {
124â†’			try {
125â†’				const content = await readFile(agentPath, "utf-8");
126â†’				subagents.push({ agentId, content });
127â†’				break;
128â†’			} catch {
129â†’				// Try next path
130â†’			}
131â†’		}
132â†’	}
133â†’
134â†’	return subagents;
135â†’}
