219â†’	async buildUploadRequest(
220â†’		session: SessionFile,
221â†’		context: UploadContext,
222â†’	): Promise<IngestSessionInput> {
223â†’		const content = await readFileWithRetry(session.transcriptPath);
224â†’
225â†’		const agentIds = extractAgentIds(content);
226â†’		const sessionDir = dirname(session.transcriptPath);
227â†’		const subagents =
228â†’			agentIds.length > 0
229â†’				? await readSubagentFiles(sessionDir, agentIds, session.sessionId)
230â†’				: [];
231â†’
232â†’		return {
233â†’			source: this.source,
234â†’			sessionId: session.sessionId,
235â†’			projectPath: session.projectPath,
236â†’			repository: context.gitInfo.repository,
237â†’			gitRemote: context.gitInfo.gitRemote,
238â†’			packageName: context.gitInfo.packageName,
239â†’			gitBranch: context.gitInfo.branch,
240â†’			gitSha: context.gitInfo.sha,
241â†’			tag: context.tag,
242â†’			content,
243â†’			subagents: subagents.length > 0 ? subagents : undefined,
244â†’			organizationId: context.organizationId,
245â†’		};
246â†’	}
