248â†’	extractTimestamps(content: string): {
249â†’		sessionDate: string;
250â†’		lastInteractionDate: string;
251â†’	} | null {
252â†’		let min: string | null = null;
253â†’		let max: string | null = null;
254â†’
255â†’		for (const line of content.split("\n")) {
256â†’			if (!line) continue;
257â†’			let parsed: { type?: string; timestamp?: string };
258â†’			try {
259â†’				parsed = JSON.parse(line);
260â†’			} catch {
261â†’				continue;
262â†’			}
263â†’			if (
264â†’				(parsed.type === "user" || parsed.type === "assistant") &&
265â†’				parsed.timestamp
266â†’			) {
267â†’				const ts = parsed.timestamp;
268â†’				if (!min || ts < min) min = ts;
269â†’				if (!max || ts > max) max = ts;
270â†’			}
271â†’		}
272â†’
273â†’		if (!min || !max) return null;
274â†’
275â†’		return { sessionDate: min, lastInteractionDate: max };
276â†’	}
