/**
 * Get projects worked on by a developer
 */
export async function getDeveloperProjects(
	orgId: string,
	userId: string,
	days = 30,
): Promise<DeveloperProject[]> {
	const org = escapeString(orgId);
	const uid = escapeString(userId);
	const d = Number(days);

	const query = `
    SELECT
      project_path,
      COUNT(*) as sessions,
      round(SUM(actual_duration_min), 2) as total_duration_min,
      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
      toString(min(session_date)) as first_session,
      toString(max(session_date)) as last_session
    FROM rudel.session_analytics
    WHERE user_id = '${uid}'
      AND ${buildDateFilter(d)}
      AND organization_id = '${org}'
      AND project_path != ''
    GROUP BY project_path
    ORDER BY sessions DESC
  `;

	const results = await queryClickhouse<DeveloperProject>(query);

	return results.map((project) => ({
		...project,
		project_name: extractProjectName(project.project_path),
	}));
}

